/**
 * HUB DE PERSISTENCIA v60.7.5
 */
const input = $input.first().json;

function buscarRecurse(obj) {
    if (typeof obj === 'string') {
        const s = obj.trim();
        return (s.toLowerCase().endsWith('.xlsx')) ? s : null;
    }
    if (obj && typeof obj === 'object') {
        for (const key in obj) {
            const result = buscarRecurse(obj[key]);
            if (result) return result;
        }
    }
    return null;
}

const lista_items = $('Una lista JSON').all().map(i => 
    i.json.nombre_archivo?.toLowerCase() || 
    Object.values(i.json)[0]?.toLowerCase()
).filter(v => typeof v === 'string' && v.endsWith('.xlsx'));

let estado_previo = "";
try {
    const bin_data = $('Leer Estado').first().binary?.data;
    if (bin_data) {
        estado_previo = Buffer.from(bin_data.data, 'base64').toString().trim();
    }
} catch(e) {}

let nombre_detectado = buscarRecurse(input);
let final_filename = "";
let estado_msj = "";
let error = false;

if (nombre_detectado) {
    const encontrado = lista_items.find(l => l.toLowerCase() === nombre_detectado.toLowerCase());
    if (encontrado) {
        final_filename = encontrado;
        estado_msj = `Archivo ${encontrado} detectado.`;
    } else {
        error = true;
        estado_msj = `El archivo '${nombre_detectado}' no existe. Disponibles: ${lista_items.join(', ')}`;
    }
} else if (estado_previo && lista_items.includes(estado_previo.toLowerCase())) {
    final_filename = estado_previo;
    estado_msj = `Usando activo: ${estado_previo}.`;
} else {
    error = true;
    estado_msj = "No hay archivo activo. Selecciona uno.";
}

return {
  nombre_archivo: final_filename ? `C:/Users/admin/.n8n-files/${final_filename}` : "undefined",
  solo_nombre: final_filename,
  operacion: (input.operacion || "lectura").toLowerCase(),
  filtro_filas: input.filtro_filas || "",
  filtro_cols: input.filtro_columnas || "",
  datos: input.datos || null,
  ruta_valida: !error,
  mensaje: estado_msj
};

const items = $input.all();
const config = $('Unificador Contexto').first().json;

if (items.length === 0 || (items[0].json && (items[0].json.error || items[0].json.message))) {
    return [{ json: { estado: "ERROR", mensaje: "Error al procesar el archivo." } }];
}

let datos = items.map(i => i.json);
let msj_extra = "";

if (config.filtro_filas) {
    const regex = new RegExp(config.filtro_filas, 'i');
    datos = datos.filter(d => Object.values(d).some(v => regex.test(String(v))));
}

switch(config.operacion) {
    case 'actualizar':
        if (config.datos) {
            datos = datos.map(row => ({ ...row, ...config.datos }));
            msj_extra = "Fila actualizada.";
        }
        break;
    case 'agregar_fila':
        if (config.datos) {
            datos.push(config.datos);
            msj_extra = "Fila agregada.";
        }
        break;
}

return [{
  json: {
    estado: "EXITO",
    mensaje: msj_extra || config.mensaje,
    conteo: datos.length,
    resultados: datos.slice(0, 15),
    __datos_completos: datos
  }
}];
